/**
 * EGDesk Helper Functions for Next.js
 *
 * Type-safe helpers for EGDesk user data, FinanceHub (banks, cards, Hometax, promissory notes),
 * internal knowledge / business identity / company research (MCP), Korean law (MCP), and browser recorder replay.
 * Works in both client and server components.
 *
 * Generated by @egdesk/next-api-plugin — do not edit by hand.
 *
 * Schema files:
 *  - egdesk.schema.ts  — committed seed schema (edit this; commit to git)
 *  - egdesk.config.ts  — auto-generated runtime snapshot (gitignored; do not edit)
 */

import { EGDESK_CONFIG } from './egdesk.config';

/**
 * Resolve EGDesk tunnel basePath for client-side fetch.
 * Next.js basePath does NOT apply to raw fetch() — prepend manually in production.
 */
export function getEgdeskBasePath(): string {
  if (typeof window === 'undefined') {
    return (
      (typeof process !== 'undefined' && process.env?.NEXT_PUBLIC_EGDESK_BASE_PATH) ||
      (typeof process !== 'undefined' && process.env?.EGDESK_BASE_PATH) ||
      ''
    );
  }

  const fromEnv =
    (typeof process !== 'undefined' && process.env?.NEXT_PUBLIC_EGDESK_BASE_PATH) || '';
  if (fromEnv) return fromEnv;

  // Fallback: detect /t/{tunnelId}/p/{projectName} from the current URL
  const parts = window.location.pathname.split('/').filter(Boolean);
  if (parts[0] === 't' && parts.length >= 4 && parts[2] === 'p') {
    return `/${parts.slice(0, 4).join('/')}`;
  }
  return '';
}

/**
 * Fetch wrapper that prepends EGDesk basePath to relative URLs.
 * Use for /api/* routes and /__*_proxy paths in client components.
 */
export async function apiFetch(path: string, options?: RequestInit): Promise<Response> {
  const basePath = getEgdeskBasePath();
  const url =
    path.startsWith('/') && !path.startsWith('//') ? `${basePath}${path}` : path;
  return fetch(url, options);
}

/** Build EGDesk routing headers (project-id + env) for server-side direct calls. */
function buildServerEgdeskHeaders(): Record<string, string> {
  const headers: Record<string, string> = { 'Content-Type': 'application/json' };
  const apiKey =
    (typeof process !== 'undefined' && process.env?.NEXT_PUBLIC_EGDESK_API_KEY) ||
    EGDESK_CONFIG.apiKey;
  const projectId =
    typeof process !== 'undefined' ? process.env?.NEXT_PUBLIC_EGDESK_PROJECT_ID : undefined;
  const egdeskEnv =
    typeof process !== 'undefined' ? process.env?.NEXT_PUBLIC_EGDESK_ENV : undefined;
  if (apiKey) headers['X-Api-Key'] = apiKey;
  if (projectId) headers['X-EGDesk-Project-Id'] = projectId;
  if (egdeskEnv) headers['X-EGDesk-Env'] = egdeskEnv;
  return headers;
}

/**
 * Parse EGDesk MCP `/tools/call` JSON so `error` is shown even when HTTP status is 500.
 */
async function parseEgdeskMcpToolResponse(response: Response): Promise<any> {
  const result = await response.json().catch(() => null);

  if (result && typeof result === 'object' && result.success === false) {
    const errMsg =
      typeof result.error === 'string'
        ? result.error
        : result.error != null
          ? String(result.error)
          : 'Tool call failed';
    throw new Error(errMsg);
  }

  if (!response.ok) {
    let fromBody = '';
    if (result && typeof result === 'object') {
      if (typeof result.error === 'string') fromBody = result.error;
      else if (typeof (result as { message?: string }).message === 'string') {
        fromBody = (result as { message: string }).message;
      }
    }
    throw new Error(fromBody || `HTTP ${response.status}: ${response.statusText}`);
  }

  if (!result || result.success !== true) {
    throw new Error(
      result && typeof result === 'object' && typeof result.error === 'string'
        ? result.error
        : 'Tool call failed'
    );
  }

  const content = result.result?.content?.[0]?.text;
  return content ? JSON.parse(content) : null;
}

/**
 * Call EGDesk user-data MCP tool
 *
 * - Server (API routes): Calls Egdesk API directly using EGDESK_CONFIG.apiUrl and
 *   EGDESK_CONFIG.apiKey (from env NEXT_PUBLIC_EGDESK_API_URL / NEXT_PUBLIC_EGDESK_API_KEY)
 *   so relative URLs and tunnel base path are not an issue.
 * - Client (browser): Uses /__user_data_proxy so CORS and tunnel base path still work.
 */
export async function callUserDataTool(
  toolName: string,
  args: Record<string, any> = {}
): Promise<any> {
  const body = JSON.stringify({ tool: toolName, arguments: args });

  const isServer = typeof window === 'undefined';

  let response: Response;
  if (isServer) {
    // API routes: call Egdesk directly (relative URL is invalid in Node)
    const apiUrl =
      (typeof process !== 'undefined' && process.env?.NEXT_PUBLIC_EGDESK_API_URL) ||
      EGDESK_CONFIG.apiUrl;
    response = await fetch(`${apiUrl}/user-data/tools/call`, {
      method: 'POST',
      headers: buildServerEgdeskHeaders(),
      body
    });
  } else {
    // Browser: use proxy for CORS and tunnel base path (proxy.ts injects routing headers)
    response = await apiFetch('/__user_data_proxy', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body
    });
  }

  return parseEgdeskMcpToolResponse(response);
}

