/**
 * Join one or more tables and query combined rows.
 * Use listTables() and getTableSchema() first to discover table names and columns.
 *
 * @example
 * await joinTables('orders', [
 *   { table: 'customers', on: { leftColumn: 'customer_id', rightColumn: 'id' } },
 *   { table: 'products', on: { leftColumn: 'orders.product_id', rightColumn: 'id' }, joinType: 'LEFT' },
 * ]);
 */
export async function joinTables(
  fromTable: string,
  joins: Array<{
    table: string;
    on:
      | { leftColumn: string; rightColumn: string }
      | Array<{ leftColumn: string; rightColumn: string }>;
    joinType?: 'INNER' | 'LEFT' | 'RIGHT';
  }>,
  options: {
    select?: string[];
    filters?: Record<string, string>;
    limit?: number;
    offset?: number;
    orderBy?: string;
    orderDirection?: 'ASC' | 'DESC';
  } = {}
) {
  return callUserDataTool('user_data_join', {
    fromTable,
    joins,
    ...options
  });
}

