export async function getPageIndexStructure(docId: string) {
  return callPageIndexTool('pageindex_get_structure', { doc_id: docId });
}

/** Get raw text for specific pages (e.g. pages: "5", "3,8", "5-7") */
export async function getPageIndexPages(docId: string, pages: string) {
  return callPageIndexTool('pageindex_get_pages', { doc_id: docId, pages });
}

/** Delete an indexed document */
export async function deletePageIndexDocument(docId: string) {
  return callPageIndexTool('pageindex_delete_document', { doc_id: docId });
}
